@charset "UTF-8";
:root {
  --bg-color: #f4f7f6;
  --card-bg: #ffffff;
  --primary: #2c3e50;
  --accent: #3498db;
  --text: #333;
  --border: #ddd;
}

body {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  background-color: var(--bg-color);
  color: var(--text);
  margin: 0;
  padding: 20px;
}

.dashboard {
  margin: 0 auto;
}

header {
  text-align: center;
  margin-bottom: 30px;
  color: var(--primary);
  font-size: 1.3rem;
}

header h2 {
  margin-bottom: 5px;
}

header p {
  margin-top: 0;
  color: #7f8c8d;
  font-size: 1.1rem;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 40px;
}

.card {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  text-align: center;
  border-top: 4px solid var(--accent);
  transition: transform 0.2s ease-in-out;
}

.card:hover {
  transform: translateY(-3px);
}

.card h3 {
  margin: 0;
  font-size: 1.2rem;
  color: #7f8c8d;
  text-transform: uppercase;
}

.card p {
  font-size: 2rem;
  font-weight: bold;
  margin: 10px 0 0;
}

/* New CSS for the Top 3 Findings Box */
.findings-box {
  background: var(--card-bg);
  padding: 25px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  border-left: 6px solid #e74c3c; /* Red accent for findings */
}

.findings-box h3 {
  margin-top: 0;
  color: var(--primary);
  font-size: 1.4rem;
  border-bottom: 2px solid var(--border);
  padding-bottom: 10px;
}

.findings-list {
  list-style-type: none;
  padding: 0;
  margin: 0;
}

.findings-list li {
  padding: 12px 0;
  border-bottom: 1px solid #f1f1f1;
  font-size: 1.15rem;
  line-height: 1.5;
  position: relative;
  padding-left: 25px;
}

.findings-list li:last-child {
  border-bottom: none;
}

.findings-list li::before {
  content: "⚠️";
  position: absolute;
  left: 0;
  top: 12px;
  font-size: 1.1rem;
}

/* Dynamic Badge Colors injected via JS */
.color-critical {
  color: #c0392b;
}

.color-warning {
  color: #d35400;
}

.color-safe {
  color: #27ae60;
}

