appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    // 1. Handle incoming data safely
    // You can map these directly from your Appsmith model later
    const rawData = model.data || {};

    // Example: pulling security_score from your APK json if available
    const baselineScore = rawData.security_score || 48;

    // Calculate Risk Tier dynamically based on score
    let riskTier = "High";
    let tierColor = "color-critical";
    if (baselineScore >= 80) {
      riskTier = "Low";
      tierColor = "color-safe";
    } else if (baselineScore >= 50) {
      riskTier = "Medium";
      tierColor = "color-warning";
    }

    // 2. Update the Stat Cards
    document.getElementById('baseline-score').innerText = baselineScore;
    const tierElement = document.getElementById('risk-tier');
    tierElement.innerText = riskTier;
    tierElement.className = tierColor; // Add color class

    // Mocking Delta and Drift since they require historical comparison
    document.getElementById('risk-delta').innerText = model.riskDelta || "+12 pts";
    const driftElement = document.getElementById('policy-drift');
    const driftStatus = model.policyDrift || "Detected";
    driftElement.innerText = driftStatus;
    if (driftStatus === "Detected") driftElement.classList.add("color-critical");

    // 3. Populate Top 3 Findings
    // Uses your model data if you pass an array, otherwise uses mock data compliant with the spec vocabulary
    const findings = model.topFindings || ["Observed High-Severity Exposure: Unsanctioned AI endpoint communicating with external third-party domain.", "Policy Drift Detection: 3 critical user identifiers are eligible for AI data flow contrary to declared policy.", "Client-Side AI Logic: Adversarial vector vulnerability surfaced in localized neural asset payload."];
    const findingsList = document.getElementById('top-findings-list');
    findingsList.innerHTML = ''; // Clear loading text

    // Take only the top 3
    findings.slice(0, 3).forEach(finding => {
      const li = document.createElement('li');
      li.textContent = finding;
      findingsList.appendChild(li);
    });
  });
});

